import{_ as i,I as s,g as a,j as t}from"./chunks/framework.CbuNJfvM.js";const u=JSON.parse('{"title":"known issues","description":"","frontmatter":{},"headers":[],"relativePath":"known-issues.md","filePath":"known-issues.md"}'),n={name:"known-issues.md"};function r(o,e,l,h,d,p){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="known-issues" tabindex="-1">known issues <a class="header-anchor" href="#known-issues" aria-label="Permalink to &quot;known issues&quot;">​</a></h1><p>There are numerous known issues, particularly in <a href="https://github.com/degory/ghul/issues" target="_blank" rel="noreferrer">the compiler</a> and in the <a href="https://github.com/degory/ghul-vsce/issues" target="_blank" rel="noreferrer">Visual Studio Code language extension</a>. If you encounter a problem not already recorded in a GitHub issue, please raise a new issue. If an existing issue is blocking you, please add a comment on the issue, and I&#39;ll investigate, or feel free to raise a PR.</p><p>Areas where you might particularly notice problems include:</p><h2 id="spurious-errors-reported-by-the-language-extension" tabindex="-1">spurious errors reported by the language extension <a class="header-anchor" href="#spurious-errors-reported-by-the-language-extension" aria-label="Permalink to &quot;spurious errors reported by the language extension&quot;">​</a></h2><p>There are several scenarios where you might receive spurious errors from the language extension when working in Visual Studio Code.</p><h3 id="opening-files-unrelated-to-the-project" tabindex="-1">opening files unrelated to the project <a class="header-anchor" href="#opening-files-unrelated-to-the-project" aria-label="Permalink to &quot;opening files unrelated to the project&quot;">​</a></h3><p>If you have a ghūl project open, and you open additional ghūl source files that are not related to that project, the language extension may incorrectly assume those files are part of the project. This can result in misleading errors. This issue is particularly prevalent in unit test projects, where the tests folder is nested within the project folder, causing the test source files to appear in the VSCode project explorer view. The workaround is to close the unrelated files and reload the project in Visual Studio with <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&lt;</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">ctrl</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&gt;</span></code> + <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">P</span></code> then select <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Developer</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> Reload</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> Window</span></code>. Then open a new separate VSCode window on the project folder containing the other source files you want to edit.</p><h3 id="opening-individual-files-without-a-project" tabindex="-1">opening individual files without a project <a class="header-anchor" href="#opening-individual-files-without-a-project" aria-label="Permalink to &quot;opening individual files without a project&quot;">​</a></h3><p>Similarly, opening individual ghūl source files in Visual Studio Code without opening the project root folder as a workspace can result in misleading error messages. The workaround is to close these files and then reopen VSCode, ensuring you open the project folder rather than individual files.</p><h3 id="cascade-of-follow-on-errors-after-an-initial-serious-error" tabindex="-1">cascade of follow-on errors after an initial serious error <a class="header-anchor" href="#cascade-of-follow-on-errors-after-an-initial-serious-error" aria-label="Permalink to &quot;cascade of follow-on errors after an initial serious error&quot;">​</a></h3><p>Occasionally one error in your ghūl source code can trigger a whole series of subsequent errors. This could be due to the parser failing to resynchronize with valid code following a syntax error, or, more rarely, an unrecoverable internal error in the compiler due to corrupted compiler state. The extension will recover from these issues if you address the error causing the cascade, but identifying the root cause is not always straightforward. Using <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&lt;</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">ctrl</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&gt;</span></code> + <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Z</span></code> / <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Undo</span></code> can help revert to a state before the problem arose. Alternatively, the first error in the error cascade in the file you&#39;re editing is often the culprit. If you cannot isolate the cause, feel free to raise an issue, preferably with example code that reproduces it.</p><h3 id="errors-appear-whilst-editing-and-subsequently-disappear" tabindex="-1">errors appear whilst editing and subsequently disappear <a class="header-anchor" href="#errors-appear-whilst-editing-and-subsequently-disappear" aria-label="Permalink to &quot;errors appear whilst editing and subsequently disappear&quot;">​</a></h3><p>This is a result of how the language extension and compiler operate. As you edit, the language extension buffers your changes, waiting for a pause in typing. Once you stop, the extension sends the latest version of the edited source files to the compiler, which compiles them and sends updated diagnostics back to the extension. To minimize latency for functions like code completion, the first recompilation after an edit is partial: the edited files are fully compiled, but the rest of the project is only compiled up to the global definitions. The bodies of functions, methods, and properties in unedited files are not compiled during this phase. The extension then waits longer, and if no further edits occur, it requests a full compilation of the entire project. This strategy boosts responsiveness for large projects, but can lead to spurious errors between the partial and full compilations, especially if further edits are made before the full compilation. The workaround is to wait a few seconds for the full compilation to complete.</p><h3 id="valid-errors-not-cleared-after-edits-to-correct-them" tabindex="-1">valid errors not cleared after edits to correct them <a class="header-anchor" href="#valid-errors-not-cleared-after-edits-to-correct-them" aria-label="Permalink to &quot;valid errors not cleared after edits to correct them&quot;">​</a></h3><p>Very occasionally, if you have an error in your code and you make an edit that corrects it, you may find the error doesn&#39;t disappear. This can be caused by the state machine in the extension failing to queue a compile or by the extension&#39;s copy of the diagnostic state getting out of step with the compiler. Recent changes to the compiler and language extension have greatly reduced incidences of this problem but not completely eliminated it. The workaround for the first scenario is to make another change to the source to force a recompile (adding and immediately removing a space character for example). The workaround for the second scenario is to reload your project with <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&lt;</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">ctrl</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&gt;</span></code> + <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">P</span></code> then <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Developer</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> Reload</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> Window</span></code>.</p><h2 id="limitations-of-generics" tabindex="-1">limitations of generics <a class="header-anchor" href="#limitations-of-generics" aria-label="Permalink to &quot;limitations of generics&quot;">​</a></h2><p>ghūl supports generics on classes, structs, traits, methods, unions and global functions, with type-parameter constraints (type bound, kind, <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">new</span></code>) and declared variance on traits. A few limitations remain.</p><h3 id="only-a-single-type-bound-per-parameter" tabindex="-1">only a single type bound per parameter <a class="header-anchor" href="#only-a-single-type-bound-per-parameter" aria-label="Permalink to &quot;only a single type bound per parameter&quot;">​</a></h3><p>The parser accepts <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> A</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code> — a single type bound — and <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> A</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> class</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> new</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code> — a bound combined with kind and constructor constraints. Multiple type bounds (<code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> A</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> /\\ </span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">B</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code>) are not yet supported and are rejected with a clear diagnostic.</p><h3 id="variance-is-declared-only-on-traits" tabindex="-1">variance is declared only on traits <a class="header-anchor" href="#variance-is-declared-only-on-traits" aria-label="Permalink to &quot;variance is declared only on traits&quot;">​</a></h3><p>The CLR permits variance only on interfaces, so <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">out</span></code> / <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">in</span></code> modifiers can be declared only on a trait&#39;s type parameters. Declaring variance on a class or struct is rejected at parse time.</p><p>Type variance for built-in types is fixed and is not user-declarable. Function types are contravariant in their parameters and covariant in their return; arrays of reference types are covariant; everything else (including <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">List</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code>, <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Map</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">K</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, </span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">V</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code>, <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Iterable</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code>) is invariant.</p>',22)])])}const k=i(n,[["render",r]]);export{u as __pageData,k as default};
